public class MergeSort {
    public static void sort(int[] arr, int l, int r) {
        // Input: bounds l and r
        if (l < r) {
            int m = l + (r - l) / 2; // Storage: midpoint

            // Process: recursive splits
            sort(arr, l, m);
            sort(arr, m + 1, r);

            // Process: merge sorted halves
            merge(arr, l, m, r);
        }
    }

    private static void merge(int[] arr, int l, int m, int r) {
        // Storage: calculate sizes
        int n1 = m - l + 1;
        int n2 = r - m;
        int[] L = new int[n1];
        int[] R = new int[n2];

        for (int i = 0; i < n1; ++i) L[i] = arr[l + i];
        for (int j = 0; j < n2; ++j) R[j] = arr[m + 1 + j];

        // Process: merge temporary arrays
        int i = 0, j = 0, k = l;
        while (i < n1 && j < n2) {
            if (L[i] <= R[j]) {
                arr[k] = L[i++];
            } else {
                arr[k] = R[j++];
            }
            k++;
        }
        while (i < n1) arr[k++] = L[i++];
        while (j < n2) arr[k++] = R[j++];
    }
}

